window.__QUIZ_DATA__=[{"id":"theory>Economics>2012>1>a>i","subject":"Economics","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION","question":"The diagram below represents the cost and revenue situation of a firm. use the information in the diagram to answer the question that follows.       Thy would the firm not produce at Q1","images":["data:image/png;base64,"],"marking_scheme":"The firm would not produce at Q1 because at Q1 the firm makes only normal profit but the aim is to maximize profit.","marks":"3","difficulty":"3"},{"id":"theory>Economics>2012>1>a>ii","subject":"Economics","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION","question":"The diagram below represents the cost and revenue situation of a firm. use the information in the diagram to answer the question that follows.     Thy would the firm not produce at Q3","images":["data:image/png;base64,"],"marking_scheme":"The firm would not produce at Q3 because at Q3 marginal cost (MC) would be greater than MR2 since P2 and Q2 are the equilibrium price and quantity respectively.","marks":"3","difficulty":"3"},{"id":"theory>Economics>2012>1>b","subject":"Economics","year":"2012","type":"Theory","sub_label":"b","group":"","topic":"THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION","question":"The diagram below represents the cost and revenue situation of a firm. use the information in the diagram to answer the question that follows.     How much profit does the firm make at P2?","images":["data:image/png;base64,"],"marking_scheme":"At P2, the total profit is the profit per unit, EB, multiplied by the quantity OQ2 or P2E.  Total profit therefore is EB x OQ2 or EB x P2E.","marks":"4","difficulty":"3"},{"id":"theory>Economics>2012>1>c>i","subject":"Economics","year":"2012","type":"Theory","sub_label":"i","group":"FINAL","topic":"THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION","question":"The diagram below represents the cost and revenue situation of a firm. use the information in the diagram to answer the question that follows.     If price falls to P2, What quantity would the firm produce?","images":["data:image/png;base64,"],"marking_scheme":"If price falls to P1, the firm would produce Q1","marks":"2","difficulty":"3"},{"id":"theory>Economics>2012>1>c>ii","subject":"Economics","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION","question":"The diagram below represents the cost and revenue situation of a firm. use the information in the diagram to answer the question that follows.     If price falls to P2, What type of profit does the firm make?","images":["data:image/png;base64,"],"marking_scheme":"The firm would make just normal profit.","marks":"2","difficulty":"3"},{"id":"theory>Economics>2012>1>c>iii","subject":"Economics","year":"2012","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION","question":"The diagram below represents the cost and revenue situation of a firm. use the information in the diagram to answer the question that follows.     If price falls to P2, Explain your answer in (ii)","images":["data:image/png;base64,"],"marking_scheme":"Normal profit is included in the average cost of the firm.  When price or average revenue is equal to average cost, then, it is only normal profit that is earned.","marks":"4","difficulty":"3"},{"id":"theory>Economics>2012>1>d","subject":"Economics","year":"2012","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"MARKET STRUCTURE : FORMS OF MARKET STRUCTURE","question":"The diagram below represents the cost and revenue situation of a firm. use the information in the diagram to answer the question that follows.     In which type of market is the firm operating?","images":["data:image/png;base64,"],"marking_scheme":"A perfect competitive market","marks":"2","difficulty":"3"},{"id":"theory>Economics>2012>2>a>i","subject":"Economics","year":"2012","type":"Theory","sub_label":"i","group":"FINAL","topic":"PUBLIC FINANCE : BUDGET","question":"The table below show the expected revenues and projected expenditures from the budget of a hypothetical country in 1998. Use the information in the table to answer the questions that follow  EXPECTED REVENUE ITEM AMOUNT ($ million)Rent royalties and profits 75.00Company income tax 150.00Customers and excise duties 300.00Personal income tax 80.00Fees and specific charges 60.80Value added tax 100.00     EXPECTED EXPENDITUREITEM AMOUNT (millions)General administration 220.10Maintenance of foreign missions 50.00Transfer payments 65.00Building of schools and hospitals 200.00Road construction 180.90    Calculate the total revenue from Direct taxes","images":[],"marking_scheme":"Direct tax $million Company income tax 150  Personal income tax 80   230","marks":"3","difficulty":"2"},{"id":"theory>Economics>2012>2>a>ii","subject":"Economics","year":"2012","type":"Theory","sub_label":"ii","group":"FINAL","topic":"PUBLIC FINANCE : BUDGET","question":"The table below show the expected revenues and projected expenditures from the budget of a hypothetical country in 1998. Use the information in the table to answer the questions that follow  EXPECTED REVENUE ITEM AMOUNT ($ million)Rent royalties and profits 75.00Company income tax 150.00Customers and excise duties 300.00Personal income tax 80.00Fees and specific charges 60.80Value added tax 100.00     EXPECTED EXPENDITUREITEM AMOUNT (millions)General administration 220.10Maintenance of foreign missions 50.00Transfer payments 65.00Building of schools and hospitals 200.00Road construction 180.90  Calculate the total revenue from Indirect taxes","images":[],"marking_scheme":"Indirect tax Customs excise duties 300.20 Value added tax 100.00   400.20","marks":"3","difficulty":"2"},{"id":"theory>Economics>2012>2>a>iii","subject":"Economics","year":"2012","type":"Theory","sub_label":"iii","group":"FINAL","topic":"PUBLIC FINANCE : BUDGET","question":"The table below show the expected revenues and projected expenditures from the budget of a hypothetical country in 1998. Use the information in the table to answer the questions that follow  EXPECTED REVENUE ITEM AMOUNT ($ million)Rent royalties and profits 75.00Company income tax 150.00Customers and excise duties 300.00Personal income tax 80.00Fees and specific charges 60.80Value added tax 100.00     EXPECTED EXPENDITUREITEM AMOUNT (millions)General administration 220.10Maintenance of foreign missions 50.00Transfer payments 65.00Building of schools and hospitals 200.00Road construction 180.90  Calculate the total revenue from non-tax sources","images":[],"marking_scheme":"Non-tax sourcesRent Royalty and profit 75.00Fees and specific charges 60.80 135.80","marks":"3","difficulty":"2"},{"id":"theory>Economics>2012>2>b>i","subject":"Economics","year":"2012","type":"Theory","sub_label":"i","group":"FINAL","topic":"PUBLIC FINANCE : BUDGET","question":"The table below show the expected revenues and projected expenditures from the budget of a hypothetical country in 1998. Use the information in the table to answer the questions that follow  EXPECTED REVENUE ITEM AMOUNT ($ million)Rent royalties and profits 75.00Company income tax 150.00Customers and excise duties 300.00Personal income tax 80.00Fees and specific charges 60.80Value added tax 100.00     EXPECTED EXPENDITUREITEM AMOUNT (millions)General administration 220.10Maintenance of foreign missions 50.00Transfer payments 65.00Building of schools and hospitals 200.00Road construction 180.90  Determine the total capital expenditure.","images":[],"marking_scheme":"Total capital Expenditure    Building of schools and hospital 200.00 Road construction 180.90  380.90","marks":"3","difficulty":"2"},{"id":"theory>Economics>2012>2>b>ii","subject":"Economics","year":"2012","type":"Theory","sub_label":"ii","group":"FINAL","topic":"PUBLIC FINANCE : BUDGET","question":"The table below show the expected revenues and projected expenditures from the budget of a hypothetical country in 1998. Use the information in the table to answer the questions that follow  EXPECTED REVENUE ITEM AMOUNT ($ million)Rent royalties and profits 75.00Company income tax 150.00Customers and excise duties 300.00Personal income tax 80.00Fees and specific charges 60.80Value added tax 100.00     EXPECTED EXPENDITUREITEM AMOUNT (millions)General administration 220.10Maintenance of foreign missions 50.00Transfer payments 65.00Building of schools and hospitals 200.00Road construction 180.90  Determine the recurrent expenditure","images":[],"marking_scheme":"Recurrent Expenditure   General Administration 220.10Maintenance of foreign mission 50.00Transfer of payment 65.00   335.10","marks":"3","difficulty":"2"},{"id":"theory>Economics>2012>2>c","subject":"Economics","year":"2012","type":"Theory","sub_label":"c","group":"FINAL","topic":"PUBLIC FINANCE : BUDGET","question":"The table below show the expected revenues and projected expenditures from the budget of a hypothetical country in 1998. Use the information in the table to answer the questions that follow  EXPECTED REVENUE ITEM AMOUNT ($ million)Rent royalties and profits 75.00Company income tax 150.00Customers and excise duties 300.00Personal income tax 80.00Fees and specific charges 60.80Value added tax 100.00     EXPECTED EXPENDITUREITEM AMOUNT (millions)General administration 220.10Maintenance of foreign missions 50.00Transfer payments 65.00Building of schools and hospitals 200.00Road construction 180.90  Determine whether the budget is a surplus or deficit","images":[],"marking_scheme":"Step 1: Calculate the Total Expected Revenue  \u00b7\tRent royalties and profits: $75.00 million  \u00b7\tCompany income tax: $150.00 million  \u00b7\tCustoms and excise duties: $300.00 million  \u00b7\tPersonal income tax: $80.00 million  \u00b7\tFees and specific charges: $60.80 million  \u00b7\tValue added tax: $100.00 million  Total Expected Revenue:  75.00+150.00+300.00+80.00+60.80+100.00=765.80 million75.00 + 150.00 + 300.00 + 80.00 + 60.80 + 100.00 = 765.80 \\text{ million}75.00+150.00+300.00+80.00+60.80+100.00=765.80 million    Step 2: Calculate the Total Projected Expenditures  \u00b7\tGeneral administration: $220.10 million  \u00b7\tMaintenance of foreign missions: $50.00 million  \u00b7\tTransfer payments: $65.00 million  \u00b7\tBuilding of schools and hospitals: $200.00 million  \u00b7\tRoad construction: $180.90 million  Total Projected Expenditures:  220.10+50.00+65.00+200.00+180.90=716.00 million220.10 + 50.00 + 65.00 + 200.00 + 180.90 = 716.00 \\text{ million}220.10+50.00+65.00+200.00+180.90=716.00 million    Step 3: Compare Revenue and Expenditures  \u00b7\tTotal Expected Revenue: $765.80 million  \u00b7\tTotal Projected Expenditures: $716.00 million    Since the total expected revenue ($765.80 million) is greater than the total projected expenditures ($716.00 million), the budget is in a surplus.  Surplus Amount:  765.80\u2212716.00 =49.80 million    So, the budget shows a surplus of $49.80 million.","marks":"5","difficulty":"2"},{"id":"theory>Economics>2012>3>a","subject":"Economics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : MEANING AND DETERMINANTS","question":"Explain how the following factors will affect the demand for a commodity X. A decrease in the price of a complement Y","images":[],"marking_scheme":"If the price of commodity Y which is a complement of X decreases, other things equal, more of Y will be demanded. The demand for X will therefore also increase.","marks":"5","difficulty":"2"},{"id":"theory>Economics>2012>3>b","subject":"Economics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : MEANING AND DETERMINANTS","question":"Explain how the following factors will affect the demand for a commodity X: an increase in consumer's disposable income","images":[],"marking_scheme":"If disposable income (income after tax) increases, more of commodity X will be demanded, if X is a normal good.  Less of commodity X will be demanded, if X is an inferior good.  Demand for X will not change if X is a good subject to satiety","marks":"5","difficulty":"2"},{"id":"theory>Economics>2012>3>c","subject":"Economics","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : MEANING AND DETERMINANTS","question":"Explain how the following factors will affect the demand for a commodity X.     A decrease in the supply of substitute P","images":[],"marking_scheme":"A decrease in the supply of a substitute good P will likely increase the demand for commodity X, assuming X and P are substitutes. The factors are:    -  Substitute Relationship: If commodity X and substitute P are considered substitutes, consumers view them as interchangeable. For example, if X is tea and P is coffee, a decrease in coffee supply makes coffee less available.    -  Price Impact: With a reduced supply of P, its price typically rises due to scarcity. Higher prices for P may lead consumers to switch to X, which is now relatively cheaper or more available.    -  Increased Demand for X: As consumers shift their preference from the more expensive P to X, the demand for X increases. This shift occurs because consumers seek to maximize their utility and minimize their expenditure on substitutes.","marks":"5","difficulty":"2"},{"id":"theory>Economics>2012>3>d","subject":"Economics","year":"2012","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : MEANING AND DETERMINANTS","question":"Explain how the following factors will affect the demand for a commodity X. An increase in income tax","images":[],"marking_scheme":"Increase in income tax will reduce consumers' disposable income. Other things equal, less of X will be demanded if X is a normal good. More of X will be demanded if X is an inferior good. The quantity demanded of X will not change if X is a good subject to satiety.","marks":"5","difficulty":"2"},{"id":"theory>Economics>2012>4>a","subject":"Economics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE","question":"State and explain the law of comparative cost advantage","images":[],"marking_scheme":"The law of comparative cost advantage states that even if a country is more efficient than another in producing all commodities, if each country specializes in producing those commodities in which it has comparative advantage over the other, world output would increase and all countries could become better off through trade.  Assume the production conditions in two countries  A and B as indicated below:  Output per Unit of resources in XYCountry A180 units120 unitsCountry B100 units 100 units  Country A has absolute advantage in both lines of production but has comparative advantage in producing commodity X. The opportunity cost ratio of producing X in country A is 1:2/3 (i.e 120/180) while the opportunity cost of producing X in country B is 1:1 (i.e 100/100), so country A should specialize in production of X and country B in production of Y.  If country A devotes all her resources to the production of X, and country B devotes all the resources to the production of Y, world output will be.  CountryOutputXYA360_B_200  The two countries can now exchange through trade to mutually gain from specialization.","marks":"12","difficulty":"3"},{"id":"theory>Economics>2012>4>b","subject":"Economics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE","question":"Give two limitations of the law as a theory of international trade","images":[],"marking_scheme":"Some limitations of the law are:  i. It assumes that there are no transport costs.  ii. It assumes free mobility of factors of production.  iii. The terms of trade and changes in them over time may not favour some countries.  iv. It assumes that production conditions (technology and the resource base of countries) will remain the same over time.  v. There are two countries in the world  vi. There are two commodities.  vii. There are no trade restrictions or barriers to trade.","marks":"8","difficulty":"3"},{"id":"theory>Economics>2012>5>a","subject":"Economics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"MONEY : INTRODUCTION","question":"Define money","images":[],"marking_scheme":"Money is anything that is generally acceptable in a given community as a means of payment for goods and services and for the settlement of debts.","marks":"2","difficulty":"1"},{"id":"theory>Economics>2012>5>b","subject":"Economics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"MONEY : DEMAND FOR MONEY","question":"State the three motives of holding money","images":[],"marking_scheme":"The three motives for holding money are:  i. Transactions motive - a certain amount is kept in hand for daily requirements such as for food, transport etc.  ii. Precautionary motive - consumers sometimes hold cash in reserve in case as unexpected payment has to be made e.g. medical expenses.  iii. Speculative motive - holding money to take advantage of investment opportunities in securities e.g bonds and shares.","marks":"6","difficulty":"1"},{"id":"theory>Economics>2012>5>c","subject":"Economics","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"MONEY : DEMAND FOR MONEY","question":"Mention two determinants of each of the motives for holding money","images":[],"marking_scheme":"Determinants of the motives are:  i. Transactions motive  - size of income   - interval between wage payments  - availability of credit  - family size  - the rate of interest  - the status / life style  - the general price level    ii. Precautionary motive  - size of income.  - interval between wage payments.  - availability of credit.  - family size.  - the rate of interest.  - perception of risk.  - availability of social insurance.    iii. Speculative motive  - the rate of interest  - the degree of risk aversion.","marks":"12","difficulty":"2"},{"id":"theory>Economics>2012>6>a","subject":"Economics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS","question":"Distinguish between economic activities and an economic system","images":[],"marking_scheme":"Economic activities are what people do to earn a living. For example, people are engaged in farming and trading.  Economic system on the other hand refers to the mode of production and the distribution of goods and services within which economic activities take place.","marks":"5","difficulty":"2"},{"id":"theory>Economics>2012>6>b>i","subject":"Economics","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"THEORY OF PRODUCTION (1) : CONCEPTS OF PRODUCTION","question":"Explain this term production","images":[],"marking_scheme":"Production is an activity that involves the creation of goods and services which satisfy human wants for example activities of a doctor and musician.","marks":"5","difficulty":"1"},{"id":"theory>Economics>2012>6>b>ii","subject":"Economics","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"DISTRIBUTIVE TRADE : INTRODUCTION","question":"Explain this term distribution","images":[],"marking_scheme":"Distribution: this is the process of storing and moving goods to consumers through intermediaries such as wholesalers and retailers.","marks":"5","difficulty":"1"},{"id":"theory>Economics>2012>6>b>iii","subject":"Economics","year":"2012","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"THEORY OF CONSUMER BEHAVIOUR : CONCEPT","question":"Explain this term consumption","images":[],"marking_scheme":"Consumption means the use of economic goods and services to satisfy human wants. Such goods may be consumer or producer goods e.g. consumption of foodstuffs and the services of a doctor.","marks":"5","difficulty":"1"},{"id":"theory>Economics>2012>7>a>i","subject":"Economics","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Define elasticity of demand","images":[],"marking_scheme":"Elasticity of demand is defined as the degree of responsiveness of quantity demanded of a commodity to changes in any of its determinants such as the price of the commodity, income of the buyers and prices of its substitutes.","marks":"2","difficulty":"1"},{"id":"theory>Economics>2012>7>a>ii","subject":"Economics","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Define price elasticity of demand","images":[],"marking_scheme":"Price elasticity of demand is defined as the degree of responsiveness of quantity demanded of a commodity to changes in the price of the commodity.","marks":"2","difficulty":"1"},{"id":"theory>Economics>2012>7>b","subject":"Economics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"State any four determinants of price elasticity of demand","images":[],"marking_scheme":"The determinants are:  - Nature of the commodity: That is, whether the commodity is a necessity or luxury. Necessary goods have inelastic demand while luxury goods have elastic demand.  - Substitutes: Commodities having substitutes have more elastic demand while those without substitutes have inelastic demand.  - Number of uses: Commodities with variety of uses have elastic demand.  - Habits: Goods consumed as habits have inelastic demand.  - Consumer's income: Where the percentages of customer's income spent on a commodity is large, demand tends to be price elastic and vice versa.  - The time factor: The longer it takes to find a substitute, the more inelastic is demand and vice versa.  - Level of prices: If high, demand is elastic but if low, demand is inelastic.  - The breadth of the definition of a commodity. Where a commodity is broadly defined demand tends to be price inelastic.","marks":"12","difficulty":"2"},{"id":"theory>Economics>2012>7>c>i","subject":"Economics","year":"2012","type":"Theory","sub_label":"i","group":"","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Draw curves illustrating fairly elastic demand","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Economics>2012>7>c>ii","subject":"Economics","year":"2012","type":"Theory","sub_label":"ii","group":"","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Draw curves illustrating perfectly inelastic demand","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Economics>2012>8>a","subject":"Economics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS","question":"Define market in economy","images":[],"marking_scheme":"Market in economics is defined as an arrangement by which buyers and sellers are brought into close contact for the purpose of transacting business. Such an arrangement is facilitated by telephone, telegraph system, postal communication, a particular location, etc.","marks":"2","difficulty":"1"},{"id":"theory>Economics>2012>8>b","subject":"Economics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)","question":"State any three features of monopoly","images":[],"marking_scheme":"- there is only one seller of a product;  - entry is restricted. Barriers to entry are so severe that new firms find it difficult to enter the market;  - it has the power to control price or output but not both  - there is no perfect knowledge or information about market conditions;  - there is no perfect substitute for the products sold by the monopolist.","marks":"9","difficulty":"2"},{"id":"theory>Economics>2012>8>c","subject":"Economics","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)","question":"Outline any three sources of monopoly power","images":[],"marking_scheme":"- natural monopoly - control over certain natural resources can give rise to a monopoly;  - government monopoly - this occurs when a government sets up a corporation to provide certain services and such firms are protected from competition;  - legal monopoly - monopoly can be created by law. Examples: Patent right and copyright which protect inventors and artists respectively;  - merger of firms  - technological monopoly  - huge capital required to set up the business  - limited market  - carte e.g OPEC  - take-overs","marks":"9","difficulty":"2"},{"id":"theory>Economics>2012>9>a","subject":"Economics","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET","question":"With the aid of a diagram, explain a minimum price","images":["data:image/png;base64,"],"marking_scheme":"A minimum price is a price fixed by legislation above the equilibrium, below which it is illegal to buy or sell.","marks":"5","difficulty":"3"},{"id":"theory>Economics>2012>9>b","subject":"Economics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"AGRICULTURE IN WEST AFRICA : MARKETING BOARDS","question":"State any five measures by which a minimum price for an agricultural produce can be made effective","images":[],"marking_scheme":"- Increase in demand through the promotion of exports to establish an equilibrium at the minimum price  - Increase in demand by the imposition of taxes on substitutes to raise their prices  - Increase in demand through increased advertisement.  - Increase in demand through the institution of a buffer stock scheme.  - Decrease supply by raising prices of inputs  - Reduce or withdraw subsidies in production to decrease supply  - Impose higher taxes on producers to discourage production  - Reduce taxes on the production of other commodities to attract resources into them.","marks":"15","difficulty":"3"},{"id":"theory>Economics>2012>10>a","subject":"Economics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"THEORY OF SUPPLY : MEANING AND DETERMINANTS","question":"What is supply schedule?","images":[],"marking_scheme":"A supply schedule is a table showing the various quantities of a commodity sellers are willing to sell at various prices, at a particular time.","marks":"2","difficulty":"1"},{"id":"theory>Economics>2012>10>b","subject":"Economics","year":"2012","type":"Theory","sub_label":"b","group":"","topic":"THEORY OF SUPPLY : MEANING AND DETERMINANTS","question":"Using an example, show how a market supply schedule of a product is obtained from individual supply schedules","images":[],"marking_scheme":"A market supply schedule shows the total quantities of a commodity which all the sellers of that commodity are willing to sell at various prices at a particular time. It is obtained by summing the individual supply schedules of all the sellers of the product. In the table below, the individual supply schedule of Messrs P, Q and R are summed to obtain the market supply for the commodity.  PRICE PER UNIT ($)QUANTITY SUPPLIEDQUANTITY SUPPLIEDQUANTITY SUPPLIEDMARKET SUPPLYMR. PMR. QMR. R10  20  30  40  50  60  70  8020  30  40  50  60  70  80  9015  25  35  45  55  65  75  8530  40  50  60  70  80  90  10065  95  125  155  185  215  245  275","marks":"12","difficulty":"2"},{"id":"theory>Economics>2012>10>c","subject":"Economics","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : MEANING AND DETERMINANTS","question":"State three examples of exceptional demand","images":[],"marking_scheme":"i. Fixed demand or perfectly inelastic demand e.g salt  ii. Perfectly elastic demand  iii. Expectation of future increase in price  iv. Articles of ostentation: These are goods bought at higher prices because buyers believe such goods put them in high class in the society.  v. Giffen goods: These goods for which quantity demanded diminish when price falls.","marks":"6","difficulty":"2"},{"id":"theory>Economics>2012>11>a","subject":"Economics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS","question":"Distinguish between Wants and demand","images":[],"marking_scheme":"Wants refer to the desire for goods and services. Wants are expressed but without the ability to pay the prices while effective demand is a want backed by the ability to pay the price. It is the quantity that is bought at a price.","marks":"5","difficulty":"1"},{"id":"theory>Economics>2012>11>b","subject":"Economics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : MEANING AND DETERMINANTS","question":"Distinguish between demand schedule and demand curve","images":[],"marking_scheme":"Demand schedule is a table that shows the quantities of a commodity buyers are willing to buy at different prices at a time while a demand curve is a graphical presentation of the information contained in the demand schedule. It is the locus of points showing the combination of prices and quantities demanded.","marks":"5","difficulty":"2"},{"id":"theory>Economics>2012>11>c","subject":"Economics","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : MEANING AND DETERMINANTS","question":"Distinguish between individual demand and market demand","images":[],"marking_scheme":"Individual demand is the different quantities of a commodity which a consumer would buy at different prices at a particular time market demand is the total quantity of a commodity which all consumers are willing and able to pay for at a particular time.","marks":"5","difficulty":"2"},{"id":"theory>Economics>2012>11>d","subject":"Economics","year":"2012","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND","question":"Distinguish between change in demand and change in quantity demanded","images":[],"marking_scheme":"Change in demand occurs when at the same price different quantities of a good are bought. This is shown by a shift of the demand curve, while a change in the quantity demanded occurs when at different prices different quantities are bought. This is shown by a movement along the same demand curve.","marks":"5","difficulty":"2"},{"id":"theory>Economics>2012>12>a","subject":"Economics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME","question":"Describe the output method of measuring the gross domestic product of a country","images":[],"marking_scheme":"The output method of measuring the gross domestic product involves summing up the market values of all output of the economy, sector by sector. Measurement is done using the value added method.","marks":"6","difficulty":"3"},{"id":"theory>Economics>2012>12>b","subject":"Economics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"NATIONAL INCOME : CONCEPT","question":"How is the net national product at factor cost obtained from gross domestic product?","images":[],"marking_scheme":"To the gross domestic product, we add the net factor incomes from abroad to obtain gross national product at market prices.  From the gross national product at market prices, we deduct depreciation or capital consumption allowance, to obtain net national product at market prices.  From the net national product at market prices we deduct indirect taxes and add subsidies to obtain net national product at factor cost.","marks":"10","difficulty":"3"},{"id":"theory>Economics>2012>12>c","subject":"Economics","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"NATIONAL INCOME : PROBLEMS OF NATIONAL INCOME","question":"State two problems associated with the output method","images":[],"marking_scheme":"- Double counting  - Difficulty in measuring subsistence output  - Difficulty in estimating rental value of owner-occupied houses  - Difficulty in estimating the net income from abroad  - Inaccurate data in measuring the output of the sectors.","marks":"4","difficulty":"2"}];